INSERT INTO doctor (doctor_code, doctor_name, department_code, doctor_title_code, title, specialty, doctor_des, doctor_image) VALUES ('DOC_DEPT012_4', '何娜', 'DEPT012', '02', '副主任医师', '幽门螺杆菌根除', '何娜副主任医师，从事消化内科临床工作19年，具备深厚的临床背景。他专注于幽门螺杆菌根除的诊疗，已成功治愈数千例相关患者。', 'doc_DOC_DEPT012_4.png');
